83	/**
84	 * Resolve a map of `{ name -> credentialId }` into `{ name -> secretValue }`
85	 * by calling `credentials:get` once per id.
86	 *
87	 * On failure we wrap the underlying error in a `credential-resolution-failed`
88	 * PluginError that names the ref + id (useful for debugging "which ref is
89	 * missing?") but never the value (there is no value on failure, but also
90	 * never on success — the caller sees it via the returned map).
91	 */
92	async function resolveCredentials(
93	  bus: BusLike,
94	  ctx: AgentContext,
95	  refs: Record<string, string> | undefined,
96	): Promise<Record<string, string>> {
97	  const out: Record<string, string> = {};
98	  if (refs === undefined) return out;
99	  for (const [name, id] of Object.entries(refs)) {
100	    try {
101	      const res = await bus.call<{ id: string }, { value: string }>(
102	        'credentials:get',
103	        ctx,
104	        { id },
105	      );
106	      out[name] = res.value;
107	    } catch (err) {
108	      throw new PluginError({
109	        code: 'credential-resolution-failed',
110	        plugin: PLUGIN_NAME,
111	        message: `failed to resolve credential ref '${name}' (id '${id}')`,
112	        cause: err instanceof Error ? err : undefined,
113	      });
114	    }
