        'fake-resolver',
        async (
          _ctx,
          input: { payload: Uint8Array; userId: string; ref: string },
        ): Promise<{
          value: string;
          refreshed?: { payload: Uint8Array; expiresAt?: number };
        }> => {
          if (firstCall) {
            firstCall = false;
            return {
              value: 'token-A',
              refreshed: {
                payload: bytes('refresh-token-v2'),
                expiresAt: 12345,
              },
